val prev = stock.getPreviousQuote(quote)
if (prev == null || prev.closePrice <= 0.0 || prev.atr <= 0.0) false
else {
  val qd = quote.date
  val e = stock.earnings.filter { it.reportedDate != null && it.reportedDate!!.year > 1900 && !it.reportedDate!!.isAfter(qd) }.maxByOrNull { it.reportedDate!! }
  if (e == null) false
  else {
    val rd = e.reportedDate!!
    val before = e.reportTime == "BeforeMarket"
    val gapDay = if (before) !qd.isBefore(rd) && prev.date.isBefore(rd) else qd.isAfter(rd) && !prev.date.isAfter(rd)
    if (!gapDay || stock.countTradingDaysBetween(rd, qd) > 3) false
    else (quote.openPrice - prev.closePrice) / prev.atr >= {{gapAtr}}
  }
}

